<?php
 declare(strict_types=1); namespace tapmeppe\composer\helpers; use Symfony\Component\Console\Input\InputInterface; abstract class Summon extends \Symfony\Component\Console\Command\Command { public function __construct(protected \Lime\App $app) { parent::__construct(); } protected final function describe(string $description): Summon { return $this->setDescription($description)->setHelp($description); } protected final function getParameters(InputInterface $input, array $arguments, array $options = []): array { $parameters = []; foreach ($arguments as $argument) $parameters[$argument] = $input->getArgument($argument); foreach ($options as $option) if ($value = $input->getOption($option) ?? $input->getOption($option[0])) $parameters[$option] = $value; return $parameters; } } 